import { gamesData, Game } from './games';

export interface Case {
  id: number;
  name: string;
  price_stars: number;
  image_url: string;
  category: string;
  genre: string;
  games: Game[]; // 15 игр
}

// Функция для получения случайных 15 игр (без повторов)
const getRandomGames = (count: number, excludeIds: number[] = []): Game[] => {
  const available = gamesData.filter(g => !excludeIds.includes(g.id));
  const shuffled = [...available].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
};

